using System.Collections.ObjectModel;using System.Diagnostics;using System.IO;using System.Windows;using System.Windows.Input;using System.Windows.Media;using MessagingServerManager.Core;using MessagingServerManager.Infrastructure;
namespace MessagingServerManager.App;
public sealed class ServerRowViewModel:ObservableObject
{
 public ServerDefinition Definition{get;} ServerStatus status;int? pid;TimeSpan uptime;double cpu;long memory;string health="Not checked";string? error;int? exit;
 public ServerRowViewModel(ServerDefinition d){Definition=d;status=d.Enabled?ServerStatus.Stopped:ServerStatus.Disabled;}public string Name=>Definition.Name;public string TypeText=>Definition.ServerType==ServerType.Nats?"NATS":"TIBCO RV";public string Ports=>string.Join(", ",ServerValidator.GetPorts(Definition).Where(x=>x.HasValue));public string LogFile=>Definition.LogFilePath??"—";public bool AutoStart=>Definition.StartWithApplication;
 public ServerStatus Status{get=>status;set{if(Set(ref status,value)){Raise(nameof(StatusText));Raise(nameof(StatusBrush));Raise(nameof(CanStart));Raise(nameof(CanStop));}}}public string StatusText=>Status.ToString();public Brush StatusBrush=>Status switch{ServerStatus.Running=>Brushes.LimeGreen,ServerStatus.Starting or ServerStatus.Stopping or ServerStatus.Restarting=>Brushes.Goldenrod,ServerStatus.Stopped or ServerStatus.Failed=>Brushes.OrangeRed,_=>Brushes.DarkGray};
 public int? Pid{get=>pid;set=>Set(ref pid,value);}public TimeSpan Uptime{get=>uptime;set{if(Set(ref uptime,value))Raise(nameof(UptimeText));}}public string UptimeText=>Pid is null?"—":Uptime.ToString(@"dd\.hh\:mm\:ss");public double Cpu{get=>cpu;set{if(Set(ref cpu,value))Raise(nameof(CpuText));}}public string CpuText=>$"{Cpu:F1}%";public long Memory{get=>memory;set{if(Set(ref memory,value))Raise(nameof(MemoryText));}}public string MemoryText=>$"{Memory/1048576d:F1} MB";public string Health{get=>health;set=>Set(ref health,value);}public string? LastError{get=>error;set=>Set(ref error,value);}public int? LastExitCode{get=>exit;set=>Set(ref exit,value);}public bool CanStart=>Definition.Enabled&&Status is ServerStatus.Stopped or ServerStatus.Failed;public bool CanStop=>Status is ServerStatus.Running or ServerStatus.Starting;public void RefreshDefinition(){Raise(nameof(Name));Raise(nameof(TypeText));Raise(nameof(Ports));Raise(nameof(LogFile));Raise(nameof(AutoStart));}
}
public sealed class MainViewModel:ObservableObject,IDisposable
{
 readonly PathResolver paths;readonly IConfigurationStore store;readonly Dictionary<ServerType,IServerAdapter> adapters;readonly ProcessManager processes;readonly LogTailReader logs=new();readonly CancellationTokenSource shutdown=new();ServerRowViewModel? selected;string logText="Select a server to view its log.";bool paused;DateTime lastUpdated;
 public ObservableCollection<ServerRowViewModel> Servers{get;}=[];public GlobalSettings Settings{get;}public ServerRowViewModel? Selected{get=>selected;set{if(Set(ref selected,value)){RaiseCommands();_=RefreshLogAsync();}}}public string LogText{get=>logText;set=>Set(ref logText,value);}public bool IsLogPaused{get=>paused;set=>Set(ref paused,value);}public DateTime LastUpdated{get=>lastUpdated;set{if(Set(ref lastUpdated,value))Raise(nameof(LastUpdatedText));}}public string LastUpdatedText=>LastUpdated==default?"Waiting for refresh":$"Last updated: {LastUpdated:G}";
 public ICommand AddServerCommand{get;}public ICommand EditServerCommand{get;}public ICommand DeleteServerCommand{get;}public ICommand StartServerCommand{get;}public ICommand StopServerCommand{get;}public ICommand RestartServerCommand{get;}public ICommand StartAllCommand{get;}public ICommand StopAllCommand{get;}public ICommand RestartAllCommand{get;}public ICommand RefreshCommand{get;}public ICommand OpenLogCommand{get;}public ICommand OpenLogFolderCommand{get;}public ICommand PauseLogCommand{get;}public ICommand ClearLogCommand{get;}public ICommand SettingsCommand{get;}
 public MainViewModel(PathResolver p,IConfigurationStore s,IEnumerable<IServerAdapter> a,GlobalSettings settings){paths=p;store=s;adapters=a.ToDictionary(x=>x.ServerType);Settings=settings;processes=new(a,settings);processes.ProcessExited+=OnExited;AddServerCommand=new RelayCommand(Add);EditServerCommand=new RelayCommand(Edit,()=>Selected is not null);DeleteServerCommand=new RelayCommand(Delete,()=>Selected is not null);StartServerCommand=new AsyncRelayCommand(StartSelectedAsync,()=>Selected?.CanStart==true);StopServerCommand=new AsyncRelayCommand(StopSelectedAsync,()=>Selected?.CanStop==true);RestartServerCommand=new AsyncRelayCommand(RestartSelectedAsync,()=>Selected?.CanStop==true);StartAllCommand=new AsyncRelayCommand(()=>ForEachAsync(x=>x.CanStart,StartAsync));StopAllCommand=new AsyncRelayCommand(()=>ForEachAsync(x=>x.CanStop,StopAsync));RestartAllCommand=new AsyncRelayCommand(()=>ForEachAsync(x=>x.CanStop,RestartAsync));RefreshCommand=new AsyncRelayCommand(RefreshAllAsync);OpenLogCommand=new RelayCommand(()=>OpenPath(LogPath(Selected!),false),()=>Selected is not null&&!string.IsNullOrWhiteSpace(Selected.Definition.LogFilePath));OpenLogFolderCommand=new RelayCommand(()=>OpenPath(LogPath(Selected!),true),()=>Selected is not null&&!string.IsNullOrWhiteSpace(Selected.Definition.LogFilePath));PauseLogCommand=new RelayCommand(()=>IsLogPaused=!IsLogPaused);ClearLogCommand=new RelayCommand(()=>LogText="");SettingsCommand=new RelayCommand(EditSettings);}
 public async Task InitializeAsync(){Directory.CreateDirectory(paths.Resolve(Settings.LoggingRootDirectory));Directory.CreateDirectory(paths.Resolve("sample-config"));await EnsureSamplesAsync();var defs=await store.LoadAsync("servers.json",Defaults());foreach(var d in defs)Servers.Add(new(d));Selected=Servers.FirstOrDefault();if(Settings.AutoStartEnabledServers)foreach(var r in Servers.Where(x=>x.Definition.Enabled&&x.Definition.StartWithApplication))await StartAsync(r);_=MonitorLoopAsync(shutdown.Token);}
 async Task EnsureSamplesAsync(){var n=paths.Resolve("sample-config/nats-server.conf");if(!File.Exists(n))await File.WriteAllTextAsync(n,"server_name: local-nats\nport: 4222\nhttp: 8222\nlog_file: 'logs/nats/local-nats.log'\ndebug: false\ntrace: false\n");var r=paths.Resolve("sample-config/rvdaemon.args.txt");if(!File.Exists(r))await File.WriteAllTextAsync(r,"# Verify flags against your installed TIBCO RV version\n-service 7500 -http 7580\n");}
 static List<ServerDefinition> Defaults()=>[new(){Name="Local NATS",Enabled=false,Executable="nats-server.exe",LaunchMode=LaunchMode.ConfigFile,ConfigFilePath="sample-config/nats-server.conf",LogFilePath="nats/local-nats.log",Nats=new(){ServerName="local-nats",ClientPort=4222,MonitoringPort=8222}},new(){Name="Local RV Daemon",ServerType=ServerType.TibcoRendezvous,Enabled=false,Executable="rvdaemon.exe",LaunchMode=LaunchMode.ManagedOptions,LogFilePath="tibrv/local-rvdaemon.log",TibRv=new(){Service=7500,HttpAdministrationPort=7580}}];
 async Task MonitorLoopAsync(CancellationToken ct){using var timer=new PeriodicTimer(TimeSpan.FromSeconds(Math.Max(1,Settings.MonitoringIntervalSeconds)));try{while(await timer.WaitForNextTickAsync(ct)){await RefreshAllAsync();if(!IsLogPaused)await RefreshLogAsync();}}catch(OperationCanceledException){}}
 async Task RefreshAllAsync(){foreach(var r in Servers)await RefreshAsync(r);LastUpdated=DateTime.Now;}async Task RefreshAsync(ServerRowViewModel r){var m=processes.Get(r.Definition.Id);if(m is null){r.Pid=null;r.Cpu=0;r.Memory=0;r.Status=r.Definition.Enabled?ServerStatus.Stopped:ServerStatus.Disabled;return;}try{var p=m.Process;var now=DateTime.UtcNow;var cpu=p.TotalProcessorTime;r.Cpu=CpuUsageCalculator.Calculate(cpu-m.PreviousCpu,now-m.PreviousSampleUtc,Environment.ProcessorCount);m.PreviousCpu=cpu;m.PreviousSampleUtc=now;r.Pid=p.Id;r.Uptime=now-p.StartTime.ToUniversalTime();r.Memory=p.WorkingSet64;var h=await adapters[r.Definition.ServerType].CheckHealthAsync(r.Definition,new(p.Id,p.StartTime.ToUniversalTime(),r.Definition.Executable),shutdown.Token);r.Health=h.Message;r.Status=h.IsHealthy?ServerStatus.Running:ServerStatus.Starting;}catch(Exception ex){r.LastError=ex.Message;r.Status=ServerStatus.Failed;}}
 async Task StartSelectedAsync(){if(Selected is not null)await StartAsync(Selected);}async Task StopSelectedAsync(){if(Selected is not null)await StopAsync(Selected);}async Task RestartSelectedAsync(){if(Selected is not null)await RestartAsync(Selected);}async Task StartAsync(ServerRowViewModel r){var v=ServerValidator.Validate(r.Definition,Servers.Select(x=>x.Definition),paths.Resolve);if(!v.IsValid){MessageBox.Show(string.Join("\n",v.Errors),"Cannot start",MessageBoxButton.OK,MessageBoxImage.Warning);return;}try{r.Status=ServerStatus.Starting;await processes.StartAsync(r.Definition,shutdown.Token);await RefreshAsync(r);}catch(Exception ex){r.LastError=ex.Message;r.Status=ServerStatus.Failed;}RaiseCommands();}async Task StopAsync(ServerRowViewModel r){if(Settings.ConfirmForceKill&&r.Definition.ForceKillAfterTimeout&&MessageBox.Show("If graceful shutdown times out, the process tree will be force-killed. Continue?","Stop server",MessageBoxButton.YesNo,MessageBoxImage.Warning)!=MessageBoxResult.Yes)return;r.Status=ServerStatus.Stopping;var x=await processes.StopAsync(r.Definition,shutdown.Token);if(!x.Stopped){r.LastError=x.Error;r.Status=ServerStatus.Failed;}else r.Status=ServerStatus.Stopped;RaiseCommands();}async Task RestartAsync(ServerRowViewModel r){r.Status=ServerStatus.Restarting;try{await processes.RestartAsync(r.Definition,shutdown.Token);await RefreshAsync(r);}catch(Exception ex){r.LastError=ex.Message;r.Status=ServerStatus.Failed;}RaiseCommands();}async Task ForEachAsync(Func<ServerRowViewModel,bool> f,Func<ServerRowViewModel,Task>a){foreach(var r in Servers.Where(f).ToList())await a(r);}
 void Add(){var d=new ServerDefinition();var w=new ServerEditorWindow(d,Servers.Select(x=>x.Definition).ToList(),paths);if(w.ShowDialog()==true){Servers.Add(new(d));Selected=Servers[^1];_=SaveAsync();}}void Edit(){if(Selected is null)return;var c=Selected.Definition.Clone();var w=new ServerEditorWindow(c,Servers.Select(x=>x.Definition).ToList(),paths);if(w.ShowDialog()==true){Copy(c,Selected.Definition);Selected.RefreshDefinition();_=SaveAsync();}}void Delete(){if(Selected is null||MessageBox.Show($"Delete '{Selected.Name}'?","Confirm deletion",MessageBoxButton.YesNo,MessageBoxImage.Warning)!=MessageBoxResult.Yes)return;Servers.Remove(Selected);Selected=Servers.FirstOrDefault();_=SaveAsync();}static void Copy(ServerDefinition s,ServerDefinition d){var c=System.Text.Json.JsonSerializer.Deserialize<ServerDefinition>(System.Text.Json.JsonSerializer.Serialize(s))!;foreach(var p in typeof(ServerDefinition).GetProperties().Where(x=>x.CanWrite))p.SetValue(d,p.GetValue(c));}Task SaveAsync()=>store.SaveAsync("servers.json",Servers.Select(x=>x.Definition).ToList());void EditSettings(){var w=new SettingsWindow(Settings);if(w.ShowDialog()==true)_=store.SaveAsync("settings.json",Settings);}
 string LogPath(ServerRowViewModel r){var p=r.Definition.LogFilePath!;return Path.IsPathRooted(Environment.ExpandEnvironmentVariables(p))?paths.Resolve(p):paths.Resolve(Path.Combine(Settings.LoggingRootDirectory,p));}async Task RefreshLogAsync(){if(Selected is null||string.IsNullOrWhiteSpace(Selected.Definition.LogFilePath)){LogText="No log file is configured.";return;}try{LogText=string.Join(Environment.NewLine,await logs.ReadTailAsync(LogPath(Selected),Settings.MaximumLogLines,shutdown.Token));}catch(Exception ex){LogText="Unable to read log: "+ex.Message;}}static void OpenPath(string p,bool folder){var t=folder?(Directory.Exists(p)?p:Path.GetDirectoryName(p)!):p;if(folder)Directory.CreateDirectory(t);try{Process.Start(new ProcessStartInfo(t){UseShellExecute=true});}catch(Exception ex){MessageBox.Show(ex.Message,"Open failed");}}void OnExited(Guid id,int? code)=>Application.Current.Dispatcher.Invoke(async()=>{var r=Servers.FirstOrDefault(x=>x.Definition.Id==id);if(r is null)return;r.LastExitCode=code;r.Status=code==0?ServerStatus.Stopped:ServerStatus.Failed;r.Pid=null;RaiseCommands();if(code!=0&&r.Definition.Enabled&&r.Definition.AutoRestart){await Task.Delay(1000);await StartAsync(r);}});void RaiseCommands(){foreach(var c in new[]{EditServerCommand,DeleteServerCommand,StartServerCommand,StopServerCommand,RestartServerCommand,OpenLogCommand,OpenLogFolderCommand})if(c is RelayCommand r)r.Raise();else if(c is AsyncRelayCommand a)a.Raise();}public void Dispose(){shutdown.Cancel();processes.Dispose();shutdown.Dispose();}
}
